export function getRealProject(id: string): RealOffPlanProject | undefined {
  return REAL_OFFPLAN_PROJECTS.find(p => p.id === id)
}

export function getRealProjectsByArea(areaId: string): RealOffPlanProject[] {
  return REAL_OFFPLAN_PROJECTS.filter(p => p.areaId === areaId)
}

export function getRealProjectsByDeveloper(devId: string): RealOffPlanProject[] {
  return REAL_OFFPLAN_PROJECTS.filter(p => p.developerId === devId)
}

export function getRealDeveloper(id: string): RealDeveloper | undefined {
  return REAL_DEVELOPERS.find(d => d.id === id)
}
